import{_ as a,c as i,o as l,ag as t}from"./chunks/framework.S-Qvb3wi.js";const u=JSON.parse('{"title":"Retention Labels: User Interface Guide","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-labels/guide.md","filePath":"enterprise/retention-labels/guide.md"}'),o={name:"enterprise/retention-labels/guide.md"};function n(r,e,s,d,h,c){return l(),i("div",null,e[0]||(e[0]=[t('<h1 id="retention-labels-user-interface-guide" tabindex="-1">Retention Labels: User Interface Guide <a class="header-anchor" href="#retention-labels-user-interface-guide" aria-label="Permalink to &quot;Retention Labels: User Interface Guide&quot;">​</a></h1><p>The retention labels management interface is located at <strong>Dashboard → Compliance → Retention Labels</strong>. It provides a comprehensive view of all configured labels and tools for creating, editing, deleting, and applying labels to individual archived emails.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Retention labels provide item-level retention control, allowing administrators to override normal retention policies for specific emails with custom retention periods. This is particularly useful for legal holds, regulatory compliance, and preserving important business communications.</p><h2 id="labels-table" tabindex="-1">Labels Table <a class="header-anchor" href="#labels-table" aria-label="Permalink to &quot;Labels Table&quot;">​</a></h2><p>The main page displays a table of all retention labels with the following columns:</p><ul><li><strong>Name:</strong> The label name and its UUID displayed underneath for reference. If a description is provided, it appears below the name in smaller text.</li><li><strong>Retention Period:</strong> The number of days emails with this label are retained, displayed as &quot;X days&quot;.</li><li><strong>Status:</strong> A badge indicating whether the label is: <ul><li><strong>Enabled</strong> (green badge): The label can be applied to new emails</li><li><strong>Disabled</strong> (gray badge): The label cannot be applied to new emails but continues to govern already-labeled emails</li></ul></li><li><strong>Created At:</strong> The date the label was created, displayed in local date format.</li><li><strong>Actions:</strong> Dropdown menu with Edit and Delete options for each label.</li></ul><p>The table is sorted by creation date in ascending order by default.</p><h2 id="creating-a-label" tabindex="-1">Creating a Label <a class="header-anchor" href="#creating-a-label" aria-label="Permalink to &quot;Creating a Label&quot;">​</a></h2><p>Click the <strong>&quot;Create New&quot;</strong> button (with plus icon) above the table to open the creation dialog.</p><h3 id="form-fields" tabindex="-1">Form Fields <a class="header-anchor" href="#form-fields" aria-label="Permalink to &quot;Form Fields&quot;">​</a></h3><ul><li><strong>Name</strong> (Required): A unique, descriptive name for the label. Maximum 255 characters.</li><li><strong>Description</strong> (Optional): A detailed explanation of the label&#39;s purpose or usage. Maximum 1000 characters.</li><li><strong>Retention Period (Days)</strong> (Required): The number of days to retain emails with this label. Must be at least 1 day.</li></ul><h3 id="example-labels" tabindex="-1">Example Labels <a class="header-anchor" href="#example-labels" aria-label="Permalink to &quot;Example Labels&quot;">​</a></h3><ul><li><p><strong>Name:</strong> &quot;Legal Hold - Project Alpha&quot;<br><strong>Description:</strong> &quot;Extended retention for emails related to ongoing litigation regarding Project Alpha intellectual property dispute&quot;<br><strong>Retention Period:</strong> 3650 days (10 years)</p></li><li><p><strong>Name:</strong> &quot;Executive Communications&quot;<br><strong>Description:</strong> &quot;Preserve important emails from C-level executives beyond normal retention periods&quot;<br><strong>Retention Period:</strong> 2555 days (7 years)</p></li><li><p><strong>Name:</strong> &quot;Financial Records Q4 2025&quot;<br><strong>Retention Period:</strong> 2190 days (6 years)</p></li></ul><h3 id="success-and-error-handling" tabindex="-1">Success and Error Handling <a class="header-anchor" href="#success-and-error-handling" aria-label="Permalink to &quot;Success and Error Handling&quot;">​</a></h3><ul><li><strong>Success</strong>: The dialog closes and a green success notification appears confirming the label was created.</li><li><strong>Name Conflict</strong>: If a label with the same name already exists, an error notification will display.</li><li><strong>Validation Errors</strong>: Missing required fields or invalid values will show inline validation messages.</li></ul><h2 id="editing-a-label" tabindex="-1">Editing a Label <a class="header-anchor" href="#editing-a-label" aria-label="Permalink to &quot;Editing a Label&quot;">​</a></h2><p>Click the <strong>Edit</strong> option from the actions dropdown on any label row to open the edit dialog.</p><h3 id="editable-fields" tabindex="-1">Editable Fields <a class="header-anchor" href="#editable-fields" aria-label="Permalink to &quot;Editable Fields&quot;">​</a></h3><ul><li><strong>Name</strong>: Can always be modified (subject to uniqueness constraint)</li><li><strong>Description</strong>: Can always be modified</li><li><strong>Retention Period</strong>: Can only be modified if the label has never been applied to any emails</li></ul><h3 id="retention-period-restrictions" tabindex="-1">Retention Period Restrictions <a class="header-anchor" href="#retention-period-restrictions" aria-label="Permalink to &quot;Retention Period Restrictions&quot;">​</a></h3><p>The edit dialog shows a warning message: &quot;Retention period cannot be modified if this label is currently applied to emails.&quot; If you attempt to change the retention period for a label that&#39;s in use, the system will return a conflict error and display an appropriate error message.</p><p>This restriction prevents tampering with active retention schedules and ensures compliance integrity.</p><h3 id="update-process" tabindex="-1">Update Process <a class="header-anchor" href="#update-process" aria-label="Permalink to &quot;Update Process&quot;">​</a></h3><ol><li>Modify the desired fields</li><li>Click <strong>Save</strong> to submit changes</li><li>The system validates the changes and updates the label</li><li>A success notification confirms the update</li></ol><h2 id="deleting-a-label" tabindex="-1">Deleting a Label <a class="header-anchor" href="#deleting-a-label" aria-label="Permalink to &quot;Deleting a Label&quot;">​</a></h2><p>Click the <strong>Delete</strong> option from the actions dropdown to open the deletion confirmation dialog.</p><h3 id="smart-deletion-behavior" tabindex="-1">Smart Deletion Behavior <a class="header-anchor" href="#smart-deletion-behavior" aria-label="Permalink to &quot;Smart Deletion Behavior&quot;">​</a></h3><p>The system uses intelligent deletion logic:</p><h4 id="hard-delete" tabindex="-1">Hard Delete <a class="header-anchor" href="#hard-delete" aria-label="Permalink to &quot;Hard Delete&quot;">​</a></h4><p>If the label has <strong>never been applied</strong> to any emails:</p><ul><li>The label is permanently removed from the system</li><li>Success message: &quot;Label deleted successfully&quot;</li></ul><h4 id="soft-disable" tabindex="-1">Soft Disable <a class="header-anchor" href="#soft-disable" aria-label="Permalink to &quot;Soft Disable&quot;">​</a></h4><p>If the label is <strong>currently applied</strong> to one or more emails:</p><ul><li>The label is marked as &quot;Disabled&quot; instead of being deleted</li><li>The label remains in the table with a &quot;Disabled&quot; status badge</li><li>Existing emails keep their retention schedule based on this label</li><li>The label cannot be applied to new emails</li><li>Success message: &quot;Label disabled successfully&quot;</li></ul><h3 id="confirmation-dialog" tabindex="-1">Confirmation Dialog <a class="header-anchor" href="#confirmation-dialog" aria-label="Permalink to &quot;Confirmation Dialog&quot;">​</a></h3><p>The deletion dialog shows:</p><ul><li><strong>Title</strong>: &quot;Delete Retention Label&quot;</li><li><strong>Description</strong>: Explains that this action cannot be undone and may disable the label if it&#39;s in use</li><li><strong>Cancel</strong> button to abort the operation</li><li><strong>Confirm</strong> button to proceed with deletion</li></ul><h2 id="applying-labels-to-emails" tabindex="-1">Applying Labels to Emails <a class="header-anchor" href="#applying-labels-to-emails" aria-label="Permalink to &quot;Applying Labels to Emails&quot;">​</a></h2><p>Retention labels can be applied to individual archived emails through the email detail pages.</p><h3 id="from-email-detail-page" tabindex="-1">From Email Detail Page <a class="header-anchor" href="#from-email-detail-page" aria-label="Permalink to &quot;From Email Detail Page&quot;">​</a></h3><ol><li>Navigate to an archived email by clicking on it from search results or the archived emails list</li><li>Look for the &quot;Retention Label&quot; section in the email metadata</li><li>If no label is applied, you&#39;ll see an &quot;Apply Label&quot; button (requires <code>delete:archive</code> permission)</li><li>If a label is already applied, you&#39;ll see: <ul><li>The current label name and retention period</li><li>&quot;Change Label&quot; and &quot;Remove Label&quot; buttons</li></ul></li></ol><h3 id="label-application-process" tabindex="-1">Label Application Process <a class="header-anchor" href="#label-application-process" aria-label="Permalink to &quot;Label Application Process&quot;">​</a></h3><ol><li>Click <strong>&quot;Apply Label&quot;</strong> or <strong>&quot;Change Label&quot;</strong></li><li>A dropdown or dialog shows all available (enabled) labels</li><li>Select the desired label</li><li>Confirm the application</li><li>The system: <ul><li>Removes any existing label from the email</li><li>Applies the new label</li><li>Records the action in the audit log</li><li>Updates the email&#39;s retention schedule</li></ul></li></ol><h3 id="one-label-per-email-rule" tabindex="-1">One Label Per Email Rule <a class="header-anchor" href="#one-label-per-email-rule" aria-label="Permalink to &quot;One Label Per Email Rule&quot;">​</a></h3><p>Each email can have at most one retention label. When you apply a new label to an email that already has a label, the previous label is automatically removed and replaced with the new one.</p><h2 id="permissions-required" tabindex="-1">Permissions Required <a class="header-anchor" href="#permissions-required" aria-label="Permalink to &quot;Permissions Required&quot;">​</a></h2><p>Different operations require different permission levels:</p><h3 id="label-management" tabindex="-1">Label Management <a class="header-anchor" href="#label-management" aria-label="Permalink to &quot;Label Management&quot;">​</a></h3><ul><li><strong>Create, Edit, Delete Labels</strong>: Requires <code>manage:all</code> permission</li><li><strong>View Labels Table</strong>: Requires <code>manage:all</code> permission</li></ul><h3 id="email-label-operations" tabindex="-1">Email Label Operations <a class="header-anchor" href="#email-label-operations" aria-label="Permalink to &quot;Email Label Operations&quot;">​</a></h3><ul><li><strong>View Email Labels</strong>: Requires <code>read:archive</code> permission</li><li><strong>Apply/Remove Email Labels</strong>: Requires <code>delete:archive</code> permission</li></ul><h2 id="status-indicators" tabindex="-1">Status Indicators <a class="header-anchor" href="#status-indicators" aria-label="Permalink to &quot;Status Indicators&quot;">​</a></h2><h3 id="enabled-labels-green-badge" tabindex="-1">Enabled Labels (Green Badge) <a class="header-anchor" href="#enabled-labels-green-badge" aria-label="Permalink to &quot;Enabled Labels (Green Badge)&quot;">​</a></h3><ul><li>Can be applied to new emails</li><li>Appears in label selection dropdowns</li><li>Fully functional for all operations</li></ul><h3 id="disabled-labels-gray-badge" tabindex="-1">Disabled Labels (Gray Badge) <a class="header-anchor" href="#disabled-labels-gray-badge" aria-label="Permalink to &quot;Disabled Labels (Gray Badge)&quot;">​</a></h3><ul><li>Cannot be applied to new emails</li><li>Does not appear in label selection dropdowns</li><li>Continues to govern retention for already-labeled emails</li><li>Can still be viewed and its details examined</li><li>Results from attempting to delete a label that&#39;s currently in use</li></ul><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="naming-conventions" tabindex="-1">Naming Conventions <a class="header-anchor" href="#naming-conventions" aria-label="Permalink to &quot;Naming Conventions&quot;">​</a></h3><ul><li>Use descriptive names that indicate purpose: &quot;Legal Hold - Case XYZ&quot;, &quot;Executive - Q4 Review&quot;</li><li>Include time periods or case references where relevant</li><li>Maintain consistent naming patterns across your organization</li></ul><h3 id="descriptions" tabindex="-1">Descriptions <a class="header-anchor" href="#descriptions" aria-label="Permalink to &quot;Descriptions&quot;">​</a></h3><ul><li>Always provide descriptions for complex or specialized labels</li><li>Include the business reason or legal requirement driving the retention period</li><li>Reference specific regulations, policies, or legal matters where applicable</li></ul><h3 id="retention-periods" tabindex="-1">Retention Periods <a class="header-anchor" href="#retention-periods" aria-label="Permalink to &quot;Retention Periods&quot;">​</a></h3><ul><li>Consider your organization&#39;s legal and regulatory requirements</li><li>Common periods: <ul><li><strong>3 years (1095 days)</strong>: Standard business records</li><li><strong>7 years (2555 days)</strong>: Financial and tax records</li><li><strong>10 years (3650 days)</strong>: Legal holds and critical business documents</li><li><strong>Permanent retention</strong>: Use very large numbers (e.g., 36500 days = 100 years)</li></ul></li></ul><h3 id="label-lifecycle" tabindex="-1">Label Lifecycle <a class="header-anchor" href="#label-lifecycle" aria-label="Permalink to &quot;Label Lifecycle&quot;">​</a></h3><ul><li>Review labels periodically to identify unused or obsolete labels</li><li>Disabled labels can accumulate over time - consider cleanup procedures</li><li>Document the purpose and expected lifecycle of each label for future administrators</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="cannot-edit-retention-period" tabindex="-1">Cannot Edit Retention Period <a class="header-anchor" href="#cannot-edit-retention-period" aria-label="Permalink to &quot;Cannot Edit Retention Period&quot;">​</a></h3><p><strong>Problem</strong>: Edit dialog shows retention period as locked or returns conflict error<br><strong>Cause</strong>: The label is currently applied to one or more emails<br><strong>Solution</strong>: Create a new label with the desired retention period instead of modifying the existing one</p><h3 id="label-not-appearing-in-email-application-dropdown" tabindex="-1">Label Not Appearing in Email Application Dropdown <a class="header-anchor" href="#label-not-appearing-in-email-application-dropdown" aria-label="Permalink to &quot;Label Not Appearing in Email Application Dropdown&quot;">​</a></h3><p><strong>Problem</strong>: A label doesn&#39;t show up when trying to apply it to an email<br><strong>Cause</strong>: The label is disabled<br><strong>Solution</strong>: Check the labels table - disabled labels show a gray &quot;Disabled&quot; badge</p><h3 id="cannot-delete-label" tabindex="-1">Cannot Delete Label <a class="header-anchor" href="#cannot-delete-label" aria-label="Permalink to &quot;Cannot Delete Label&quot;">​</a></h3><p><strong>Problem</strong>: Deletion results in label being disabled instead of removed<br><strong>Cause</strong>: The label is currently applied to emails<br><strong>Solution</strong>: This is expected behavior to preserve retention integrity. The label can only be hard-deleted if it has never been used.</p><h3 id="permission-denied-errors" tabindex="-1">Permission Denied Errors <a class="header-anchor" href="#permission-denied-errors" aria-label="Permalink to &quot;Permission Denied Errors&quot;">​</a></h3><p><strong>Problem</strong>: Cannot access label management or apply labels to emails<br><strong>Cause</strong>: Insufficient permissions<br><strong>Solution</strong>: Contact your system administrator to verify you have the required permissions:</p><ul><li><code>manage:all</code> for label management</li><li><code>delete:archive</code> for email label operations</li></ul>',76)]))}const p=a(o,[["render",n]]);export{u as __pageData,p as default};
